    } else {
      setIsPointerEventsEnabled(false);
    }
  }, [isOpen]);

  // Determine current tool from path
  const getCurrentTool = () => {
    const path = location.pathname;
    for (const tool of [...processTools, ...assistantTools]) {
      if (tool.path && path.startsWith(tool.path)) {
        return tool;
      }
    }
    return null;
